const PeerTransportParameterValidationError = Error || error{
    VersionNegotiationError,
};

fn peerTransportParameterValidationErrorAsPublic(err: PeerTransportParameterValidationError) Error {
    return switch (err) {
        error.VersionNegotiationError => error.InvalidPacket,
        error.ConnectionClosed => error.ConnectionClosed,
        error.InvalidPacket => error.InvalidPacket,
        error.CryptoError => error.CryptoError,
        error.Internal => error.Internal,
        error.OutOfMemory => error.OutOfMemory,
        error.BufferTooSmall => error.BufferTooSmall,
        error.FlowControlBlocked => error.FlowControlBlocked,
        error.StreamClosed => error.StreamClosed,
        error.InvalidStream => error.InvalidStream,
    };
}

fn statelessResetTokensEqual(
    a: [packet.stateless_reset_token_len]u8,
    b: [packet.stateless_reset_token_len]u8,
) bool {
    return std.crypto.timing_safe.eql([packet.stateless_reset_token_len]u8, a, b);
}

fn validateInitialDestinationConnectionIdLength(dcid: []const u8) Error!void {
    if (dcid.len < min_initial_destination_connection_id_len or dcid.len > max_connection_id_len) {
        return error.InvalidPacket;
    }
}

fn protectedLongDatagramKeysForSpace(
    space: PacketNumberSpace,
    keys: protection.Aes128PacketProtectionKeys,
) Error!ProtectedLongDatagramKeys {
    return switch (space) {
        .initial => .{ .initial = keys },
        .handshake => .{ .handshake = keys },
        .application => error.InvalidPacket,
    };
}

/// Endpoint/event-loop owner for QUIC loss detection timer scheduling.
///
/// This helper does not own `Connection` objects and performs no socket I/O.
/// Call `armFromConnection()` after packet send, ACK processing, key discard, or
/// timer service to mirror the connection's current aggregate recovery timer.
/// `earliestDeadline()` returns the next connection handle to wake, and
/// `serviceConnection()` dispatches the due timer through the connection helper
/// before refreshing endpoint scheduling state.
pub const EndpointLossDetectionTimers = struct {
    allocator: std.mem.Allocator,
    entries: std.ArrayList(EndpointLossDetectionTimerDeadline) = .empty,

    /// Create an empty endpoint recovery timer owner.
    pub fn init(allocator: std.mem.Allocator) EndpointLossDetectionTimers {
        return .{ .allocator = allocator };
    }

    /// Release all endpoint timer storage.
    pub fn deinit(self: *EndpointLossDetectionTimers) void {
        self.entries.deinit(self.allocator);
    }

    /// Return the number of connection timers currently armed by the endpoint.
    pub fn count(self: *const EndpointLossDetectionTimers) usize {
        return self.entries.items.len;
    }

    /// Mirror one connection's current aggregate loss/PTO timer.
    ///
    /// If the connection has no armed recovery timer, any existing endpoint
    /// entry for `connection_id` is removed. Otherwise the existing entry is
    /// updated or a new entry is appended.
    pub fn armFromConnection(
        self: *EndpointLossDetectionTimers,
        connection_id: u64,
        connection: *const Connection,
    ) Error!void {
        try self.update(connection_id, connection.lossDetectionTimerDeadlineMillis());
    }

    /// Remove one connection timer from endpoint scheduling state.
    pub fn disarmConnection(self: *EndpointLossDetectionTimers, connection_id: u64) bool {
        const index = self.findIndex(connection_id) orelse return false;
        _ = self.entries.orderedRemove(index);
        return true;
    }

    /// Return the earliest connection-level recovery timer known to the endpoint.
    pub fn earliestDeadline(self: *const EndpointLossDetectionTimers) ?EndpointLossDetectionTimerDeadline {
        if (self.entries.items.len == 0) return null;
        var earliest = self.entries.items[0];
        for (self.entries.items[1..]) |entry| {
            if (entry.timer.deadline_millis < earliest.timer.deadline_millis) {
                earliest = entry;
            }
        }
        return earliest;
    }

    /// Return one connection handle's recovery timer snapshot, if armed.
    pub fn deadlineForConnection(self: *const EndpointLossDetectionTimers, connection_id: u64) ?EndpointLossDetectionTimerDeadline {
        const index = self.findIndex(connection_id) orelse return null;
        return self.entries.items[index];
    }

    /// Service one connection's due loss detection timer and refresh scheduling.
    ///
    /// This is the endpoint event-loop bridge for a caller-owned connection
    /// selected by `earliestDeadline()`. It is safe to call before the deadline:
    /// the connection helper is a no-op and the endpoint entry is refreshed from
    /// the connection's current timer. A connection with no remaining timer is
    /// disarmed.
    pub fn serviceConnection(
        self: *EndpointLossDetectionTimers,
        connection_id: u64,
        connection: *Connection,
        now_millis: i64,
    ) Error!?EndpointLossDetectionTimerDeadline {
        const serviced = try connection.serviceLossDetectionTimer(now_millis);
        try self.armFromConnection(connection_id, connection);
        const timer = serviced orelse return null;
        return .{
            .connection_id = connection_id,
            .timer = timer,
        };
    }

    /// Set or clear a connection timer from an already computed deadline.
    pub fn update(
        self: *EndpointLossDetectionTimers,
        connection_id: u64,
        timer: ?LossDetectionTimerDeadline,
    ) Error!void {
        const index = self.findIndex(connection_id);
        if (timer) |deadline| {
            const entry = EndpointLossDetectionTimerDeadline{
                .connection_id = connection_id,
                .timer = deadline,
            };
            if (index) |existing| {
                self.entries.items[existing] = entry;
            } else {
                self.entries.append(self.allocator, entry) catch return error.OutOfMemory;
            }
        } else if (index) |existing| {
            _ = self.entries.orderedRemove(existing);
        }
    }

    fn findIndex(self: *const EndpointLossDetectionTimers, connection_id: u64) ?usize {
        for (self.entries.items, 0..) |entry, index| {
            if (entry.connection_id == connection_id) return index;
        }
        return null;
    }
};

/// Endpoint result after processing a client-side Version Negotiation response.
pub const EndpointVersionNegotiationResult = struct {
    /// Version selected from the validated Version Negotiation packet.
    selected_version: packet.Version,
    /// Config for the follow-up client connection attempt using that version.
    followup_config: Config,
    /// Route and timer cleanup applied to the superseded connection attempt.
    retired: EndpointConnectionRetireResult,
};

/// Endpoint result after accepting Version Negotiation and registering follow-up routing.
pub const EndpointVersionNegotiationFollowupResult = struct {
    /// Version Negotiation processing result, including selected version and old route cleanup.
    version_negotiation: EndpointVersionNegotiationResult,
    /// Route installed for the next client Initial Source CID.
    followup_route: endpoint.RouteResult,
};

/// Endpoint result after accepting Version Negotiation and creating the follow-up connection.
pub const EndpointVersionNegotiationHandoffResult = struct {
    /// Version Negotiation endpoint state changes and follow-up route.
    followup: EndpointVersionNegotiationFollowupResult,
    /// Newly initialized client connection for the selected version.
    ///
    /// The caller owns this connection and must call `deinit()`.
    followup_connection: Connection,
};

/// Endpoint result after accepting Version Negotiation and emitting a follow-up Initial.
pub const EndpointVersionNegotiationProtectedInitialResult = struct {
    /// Endpoint-owned follow-up route and initialized client connection.
    handoff: EndpointVersionNegotiationHandoffResult,
    /// Caller-keyed protected Initial datagram emitted by `handoff.followup_connection`.
    ///
    /// The caller owns these bytes and must free them with the same allocator
    /// used by `handoff.followup_connection`.
    initial_datagram: []u8,
};

/// Caller-owned connection reference used by aggregate endpoint scheduling.
pub const EndpointConnectionView = struct {
    /// Caller-owned connection handle used by endpoint routing and timers.
    connection_id: u64,
    /// Caller-owned connection state. The lifecycle does not take ownership.
    connection: *const Connection,
};

/// Mutable caller-owned connection reference used by socket-loop deadline work.
pub const EndpointConnectionPollView = struct {
    /// Caller-owned connection handle used by endpoint routing and timers.
    connection_id: u64,
    /// Caller-owned connection state. The lifecycle does not take ownership.
    connection: *Connection,
    /// Destination connection ID to use when a due recovery wakeup emits a packet.
    destination_connection_id: []const u8,
    /// Source connection ID for long-header Handshake recovery packets.
    source_connection_id: []const u8 = &.{},
};

/// Mutable caller-owned connection plus explicit installed-key output options.
pub const EndpointConnectionInstalledKeyPollView = struct {
    /// Caller-owned connection handle used by endpoint routing and timers.
    connection_id: u64,
    /// Caller-owned connection state. The lifecycle does not take ownership.
