            .route = route,
            .drain = try self.processProtectedZeroRttDatagramAndDrainShortDatagrams(
                connection_id,
                connection,
                now_millis,
                receive_keys,
                datagram,
                dcid,
                send_keys,
                out,
            ),
        };
    }

    /// Route caller-keyed 0-RTT input through close propagation, then poll output.
