    ) Error!EndpointCryptoBackendDriveDatagramDrainResult {
        try self.processProtectedShortDatagramWithInstalledKeys(
            connection_id,
            connection,
            now_millis,
            dcid_len,
            datagram,
        );
        return self.driveCryptoBackendInSpaceAndDrainDatagrams(
            connection_id,
            connection,
            backend_space,
            backend,
            scratch,
            drain_now_millis,
            poll_options,
            out,
