    pub fn processRoutedProtectedShortDatagramWithInstalledKeysAndDriveCryptoBackendInSpaceWithCompatibleVersionAndDrainDatagrams(
        self: *EndpointConnectionLifecycle,
        connection_id: u64,
        connection: *Connection,
