    try std.testing.expectError(error.InvalidPacket, Connection.init(std.testing.allocator, .client, .{
        .chosen_version = @enumFromInt(0),
        .available_versions = &v1_only,
    }));
    try std.testing.expectError(error.InvalidPacket, Connection.init(std.testing.allocator, .client, .{
        .chosen_version = .v1,
        .available_versions = &[_]packet.Version{.v2},
    }));

