test "driveCryptoBackendInSpace exchanges transport parameter bytes with backend" {
    const MockBackend = struct {
        local_transport_parameters: std.ArrayList(u8) = .empty,
        peer_transport_parameters: []const u8,
        peer_sent: bool = false,

        fn deinit(self: *@This()) void {
            self.local_transport_parameters.deinit(std.testing.allocator);
        }

        fn backend(self: *@This()) CryptoBackend {
            return .{
                .context = self,
                .receive = receive,
                .pull = pull,
                .set_local_transport_parameters = setLocalTransportParameters,
                .pull_peer_transport_parameters = pullPeerTransportParameters,
            };
        }

        fn receive(_: *anyopaque, _: PacketNumberSpace, _: []const u8) Error!void {}

        fn pull(_: *anyopaque, _: PacketNumberSpace, _: []u8) Error!?[]const u8 {
            return null;
        }

        fn setLocalTransportParameters(context: *anyopaque, data: []const u8) Error!void {
            const self: *@This() = @ptrCast(@alignCast(context));
            self.local_transport_parameters.appendSlice(std.testing.allocator, data) catch return error.OutOfMemory;
        }

        fn pullPeerTransportParameters(context: *anyopaque, out_buf: []u8) Error!?[]const u8 {
            const self: *@This() = @ptrCast(@alignCast(context));
            if (self.peer_sent) return null;
            if (out_buf.len < self.peer_transport_parameters.len) return error.BufferTooSmall;
            @memcpy(out_buf[0..self.peer_transport_parameters.len], self.peer_transport_parameters);
            self.peer_sent = true;
            return out_buf[0..self.peer_transport_parameters.len];
        }
    };

    var peer_params_buf: [160]u8 = undefined;
    var peer_params_out = buffer.fixedWriter(&peer_params_buf);
    try transport_parameters.encode(peer_params_out.writer(), .{
        .max_idle_timeout = 88,
        .max_udp_payload_size = 1400,
        .initial_max_data = 1234,
        .initial_max_stream_data_bidi_local = 55,
        .initial_max_stream_data_bidi_remote = 66,
        .initial_max_stream_data_uni = 77,
        .initial_max_streams_bidi = 4,
        .initial_max_streams_uni = 5,
        .ack_delay_exponent = 5,
        .max_ack_delay = 33,
    });

    var conn = try Connection.init(std.testing.allocator, .server, .{
        .max_datagram_size = 1300,
        .ack_delay_exponent = 4,
        .max_ack_delay_ms = 44,
        .initial_max_data = 999,
    });
    defer conn.deinit();

    var backend = MockBackend{ .peer_transport_parameters = peer_params_out.getWritten() };
    defer backend.deinit();
    var scratch: [256]u8 = undefined;
    const progress = try conn.driveCryptoBackendInSpace(.initial, backend.backend(), &scratch);

    try std.testing.expect(progress.local_transport_parameters_bytes > 0);
    try std.testing.expectEqual(progress.local_transport_parameters_bytes, backend.local_transport_parameters.items.len);
    try std.testing.expectEqual(peer_params_out.getWritten().len, progress.peer_transport_parameters_bytes);
    try std.testing.expect(progress.peer_transport_parameters_applied);
    try std.testing.expectEqual(@as(?packet.Version, null), progress.peer_compatible_version_selected);

    var parsed_local = try transport_parameters.parse(backend.local_transport_parameters.items, std.testing.allocator);
    defer parsed_local.deinit(std.testing.allocator);
    try std.testing.expectEqual(@as(u64, 999), parsed_local.initial_max_data);
    try std.testing.expectEqual(@as(u64, 4), parsed_local.ack_delay_exponent);
    try std.testing.expectEqual(@as(u64, 44), parsed_local.max_ack_delay);
    try std.testing.expectEqual(@as(u64, 1300), parsed_local.max_udp_payload_size);

    try std.testing.expectEqual(@as(u64, 1234), conn.peer_max_data);
    try std.testing.expectEqual(@as(u64, 55), conn.peer_initial_max_stream_data_bidi_local);
    try std.testing.expectEqual(@as(u64, 66), conn.peer_initial_max_stream_data_bidi_remote);
    try std.testing.expectEqual(@as(u64, 77), conn.peer_initial_max_stream_data_uni);
    try std.testing.expectEqual(@as(u64, 4), conn.peer_max_streams_bidi);
    try std.testing.expectEqual(@as(u64, 5), conn.peer_max_streams_uni);
    try std.testing.expectEqual(@as(u64, 5), conn.peer_ack_delay_exponent);
    try std.testing.expectEqual(@as(u64, 88), conn.peer_max_idle_timeout_ms);
    try std.testing.expectEqual(@as(usize, 1400), conn.peer_max_udp_payload_size);
    try std.testing.expectEqual(@as(u64, 33), conn.recovery_state.max_ack_delay_ms);
}

test "TlsBackend adapter drives C ABI callbacks through CryptoBackend" {
    const CBackend = struct {
        local_transport_parameters: [256]u8 = undefined,
        local_transport_parameters_len: usize = 0,
        received: [64]u8 = undefined,
        received_len: usize = 0,
        peer_transport_parameters: []const u8,
        peer_transport_parameters_sent: bool = false,
        outbound: []const u8,
        outbound_sent: bool = false,
        handshake_secrets: HandshakeTrafficSecrets,
        handshake_secrets_sent: bool = false,

        fn receive(
            context: *anyopaque,
            space: TlsBackendPacketSpace,
            data: [*]const u8,
            data_len: usize,
        ) callconv(.c) TlsBackendStatus {
            if (space != .handshake) return .crypto_error;
            const self: *@This() = @ptrCast(@alignCast(context));
            if (data_len > self.received.len) return .buffer_too_small;
            @memcpy(self.received[0..data_len], data[0..data_len]);
            self.received_len = data_len;
            return .ok;
        }

        fn pull(
            context: *anyopaque,
            space: TlsBackendPacketSpace,
            out: [*]u8,
            out_len: usize,
            written_len: *usize,
        ) callconv(.c) TlsBackendStatus {
            if (space != .handshake) return .crypto_error;
            const self: *@This() = @ptrCast(@alignCast(context));
            if (self.outbound_sent) return .pending;
            if (out_len < self.outbound.len) return .buffer_too_small;
            @memcpy(out[0..self.outbound.len], self.outbound);
            written_len.* = self.outbound.len;
            self.outbound_sent = true;
            return .ok;
        }

        fn setLocalTransportParameters(
            context: *anyopaque,
            data: [*]const u8,
            data_len: usize,
        ) callconv(.c) TlsBackendStatus {
            const self: *@This() = @ptrCast(@alignCast(context));
            if (data_len > self.local_transport_parameters.len) return .buffer_too_small;
            @memcpy(self.local_transport_parameters[0..data_len], data[0..data_len]);
            self.local_transport_parameters_len = data_len;
            return .ok;
        }

        fn pullPeerTransportParameters(
            context: *anyopaque,
            out: [*]u8,
            out_len: usize,
            written_len: *usize,
        ) callconv(.c) TlsBackendStatus {
            const self: *@This() = @ptrCast(@alignCast(context));
            if (self.peer_transport_parameters_sent) return .pending;
            if (out_len < self.peer_transport_parameters.len) return .buffer_too_small;
            @memcpy(out[0..self.peer_transport_parameters.len], self.peer_transport_parameters);
            written_len.* = self.peer_transport_parameters.len;
            self.peer_transport_parameters_sent = true;
            return .ok;
        }

        fn pullHandshakeTrafficSecrets(
            context: *anyopaque,
            out: *HandshakeTrafficSecrets,
        ) callconv(.c) TlsBackendStatus {
            const self: *@This() = @ptrCast(@alignCast(context));
            if (self.handshake_secrets_sent) return .pending;
            out.* = self.handshake_secrets;
            self.handshake_secrets_sent = true;
            return .ok;
        }

        fn handshakeConfirmed(_: *anyopaque) callconv(.c) bool {
            return true;
        }
    };

    var peer_params_buf: [96]u8 = undefined;
    var peer_params_out = buffer.fixedWriter(&peer_params_buf);
    try transport_parameters.encode(peer_params_out.writer(), .{
        .initial_max_data = 2048,
        .initial_max_stream_data_bidi_local = 512,
        .initial_max_streams_bidi = 2,
    });

    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);

    var c_backend = CBackend{
        .peer_transport_parameters = peer_params_out.getWritten(),
        .outbound = "server tls flight",
        .handshake_secrets = .{
            .local = secrets.server.secret,
            .peer = secrets.client.secret,
        },
    };
    var tls_backend = TlsBackend{
        .context = &c_backend,
        .receive = CBackend.receive,
        .pull = CBackend.pull,
        .set_local_transport_parameters = CBackend.setLocalTransportParameters,
        .pull_peer_transport_parameters = CBackend.pullPeerTransportParameters,
        .pull_handshake_traffic_secrets = CBackend.pullHandshakeTrafficSecrets,
        .handshake_confirmed = CBackend.handshakeConfirmed,
    };

    var conn = try Connection.init(std.testing.allocator, .server, .{});
    defer conn.deinit();

    var datagram: [64]u8 = undefined;
    var in = buffer.fixedWriter(&datagram);
    try frame.encodeFrame(in.writer(), .{ .crypto = .{
        .offset = 0,
        .data = "client tls flight",
    } });
    try conn.processDatagramInSpace(.handshake, 0, in.getWritten());

    var scratch: [256]u8 = undefined;
    const progress = try conn.driveCryptoBackendInSpace(.handshake, tls_backend.cryptoBackend(), &scratch);

    try std.testing.expectEqualStrings("client tls flight", c_backend.received[0..c_backend.received_len]);
    try std.testing.expect(c_backend.local_transport_parameters_len > 0);
    try std.testing.expectEqual(peer_params_out.getWritten().len, progress.peer_transport_parameters_bytes);
    try std.testing.expect(progress.peer_transport_parameters_applied);
    try std.testing.expect(progress.handshake_keys_installed);
    try std.testing.expect(progress.handshake_confirmed);
    try std.testing.expectEqual(@as(usize, 1), progress.outbound_chunks);
    try std.testing.expectEqual(c_backend.outbound.len, progress.outbound_bytes);
    try std.testing.expect(conn.hasHandshakeProtectionKeys());
    try std.testing.expectEqual(@as(u64, 2048), conn.peer_max_data);
    try std.testing.expectEqual(@as(u64, 512), conn.peer_initial_max_stream_data_bidi_local);
    try std.testing.expectEqual(@as(u64, 2), conn.peer_max_streams_bidi);
}

test "driveCryptoBackendInSpaceWithCompatibleVersion applies backend peer Version Information" {
    const Backend = struct {
        peer_transport_parameters: []const u8,
        peer_sent: bool = false,

        fn backend(self: *@This()) CryptoBackend {
            return .{
                .context = self,
                .receive = receive,
                .pull = pull,
                .pull_peer_transport_parameters = pullPeerTransportParameters,
            };
        }

        fn receive(_: *anyopaque, _: PacketNumberSpace, _: []const u8) Error!void {}

        fn pull(_: *anyopaque, _: PacketNumberSpace, _: []u8) Error!?[]const u8 {
            return null;
        }

        fn pullPeerTransportParameters(context: *anyopaque, out_buf: []u8) Error!?[]const u8 {
            const self: *@This() = @ptrCast(@alignCast(context));
            if (self.peer_sent) return null;
            if (out_buf.len < self.peer_transport_parameters.len) return error.BufferTooSmall;
            @memcpy(out_buf[0..self.peer_transport_parameters.len], self.peer_transport_parameters);
            self.peer_sent = true;
            return out_buf[0..self.peer_transport_parameters.len];
        }
    };

    const client_versions = [_]packet.Version{ .v1, .v2 };
    const server_versions = [_]packet.Version{ .v2, .v1 };
    const compatibilities = [_]VersionCompatibility{.{
        .original_version = .v1,
        .negotiated_version = .v2,
    }};
    var peer_params_buf: [128]u8 = undefined;
    var peer_params_out = buffer.fixedWriter(&peer_params_buf);
    try transport_parameters.encode(peer_params_out.writer(), .{
        .initial_max_data = 4321,
        .version_information = .{
            .chosen_version = .v1,
            .available_versions = &client_versions,
        },
    });

    var server = try Connection.init(std.testing.allocator, .server, .{
        .chosen_version = .v2,
        .available_versions = &server_versions,
    });
    defer server.deinit();

    var backend = Backend{ .peer_transport_parameters = peer_params_out.getWritten() };
    var scratch: [256]u8 = undefined;
    const progress = try server.driveCryptoBackendInSpaceWithCompatibleVersion(
        .handshake,
        backend.backend(),
        &scratch,
        &compatibilities,
    );

    try std.testing.expectEqual(peer_params_out.getWritten().len, progress.peer_transport_parameters_bytes);
    try std.testing.expect(progress.peer_transport_parameters_applied);
    try std.testing.expectEqual(@as(?packet.Version, packet.Version.v2), progress.peer_compatible_version_selected);
    try std.testing.expectEqual(@as(u64, 4321), server.peer_max_data);
    const peer_version_information = server.peerVersionInformation() orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(packet.Version.v1, peer_version_information.chosen_version);
    try std.testing.expectEqualSlices(packet.Version, &client_versions, peer_version_information.available_versions);
    try std.testing.expectEqual(
        @as(?packet.Version, packet.Version.v2),
        try server.selectPeerCompatibleVersion(&compatibilities),
    );
}

test "driveCryptoBackendInSpaceWithCompatibleVersionOrClose queues version negotiation close before output" {
    const Backend = struct {
        output_pulled: bool = false,
        peer_transport_parameters: []const u8,
        peer_sent: bool = false,

        fn backend(self: *@This()) CryptoBackend {
            return .{
                .context = self,
                .receive = receive,
                .pull = pull,
                .pull_peer_transport_parameters = pullPeerTransportParameters,
            };
        }

        fn receive(_: *anyopaque, _: PacketNumberSpace, _: []const u8) Error!void {}

        fn pull(context: *anyopaque, _: PacketNumberSpace, out_buf: []u8) Error!?[]const u8 {
            const self: *@This() = @ptrCast(@alignCast(context));
            self.output_pulled = true;
            if (out_buf.len == 0) return error.BufferTooSmall;
            out_buf[0] = 0;
            return out_buf[0..1];
        }

        fn pullPeerTransportParameters(context: *anyopaque, out_buf: []u8) Error!?[]const u8 {
            const self: *@This() = @ptrCast(@alignCast(context));
            if (self.peer_sent) return null;
            if (out_buf.len < self.peer_transport_parameters.len) return error.BufferTooSmall;
            @memcpy(out_buf[0..self.peer_transport_parameters.len], self.peer_transport_parameters);
            self.peer_sent = true;
            return out_buf[0..self.peer_transport_parameters.len];
        }
    };

    const client_versions = [_]packet.Version{ .v1, .v2 };
    const server_versions = [_]packet.Version{ .v2, .v1 };
    var peer_params_buf: [128]u8 = undefined;
    var peer_params_out = buffer.fixedWriter(&peer_params_buf);
    try transport_parameters.encode(peer_params_out.writer(), .{
        .initial_max_data = 4321,
        .version_information = .{
            .chosen_version = .v1,
            .available_versions = &client_versions,
        },
    });

    var server = try Connection.init(std.testing.allocator, .server, .{
        .chosen_version = .v2,
        .available_versions = &server_versions,
    });
    defer server.deinit();
    try server.validatePeerAddress();

    var backend = Backend{ .peer_transport_parameters = peer_params_out.getWritten() };
    var scratch: [256]u8 = undefined;
    try std.testing.expectError(
        error.InvalidPacket,
        server.driveCryptoBackendInSpaceWithCompatibleVersionOrClose(
            .handshake,
            backend.backend(),
            &scratch,
            &[_]VersionCompatibility{},
        ),
    );
    try std.testing.expect(!backend.output_pulled);
    try std.testing.expect(server.peerVersionInformation() == null);
    try std.testing.expectEqual(ConnectionState.closing, server.connectionState());

    var close_buf: [96]u8 = undefined;
    const payload = (try server.pollTx(0, &close_buf)) orelse return error.TestUnexpectedResult;
    var decoded = try frame.decodeFrameSlice(payload, std.testing.allocator);
    defer frame.deinitFrame(&decoded.frame, std.testing.allocator);
    switch (decoded.frame) {
        .connection_close => |close| {
            try std.testing.expectEqual(transport_error.codeValue(.version_negotiation_error), close.error_code);
            try std.testing.expectEqual(@as(u64, @intFromEnum(frame.FrameType.crypto)), close.frame_type);
            try std.testing.expectEqualStrings("version negotiation", close.reason_phrase);
        },
        else => return error.InvalidPacket,
    }
}

