test "EndpointConnectionLifecycle single pending-work backend loop step selects next deadline" {
    const NoopBackend = struct {
        pulls: usize = 0,

        fn backend(self: *@This()) CryptoBackend {
            return .{
                .context = self,
                .receive = receive,
                .pull = pull,
