    defer conn.deinit();
    try conn.validatePeerAddress();
    try conn.confirmHandshake();

    const path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_003),
    };
    const cid = [_]u8{ 0x75, 0x76, 0x77, 0x78 };
    try lifecycle.registerConnectionId(76, &cid, path, .{ .sequence_number = 0 });

    try conn.sendPing();
    var payload_buf: [16]u8 = undefined;
    _ = (try conn.pollTx(10, &payload_buf)) orelse return error.TestUnexpectedResult;
    const idle_deadline = conn.idleTimeoutDeadlineMillis() orelse return error.TestUnexpectedResult;

    var backend = Backend{ .peer_transport_parameters = peer_params_out.getWritten() };
    var scratch: [256]u8 = undefined;
    const result = try lifecycle.processPendingWorkAndDriveCryptoBackendInSpaceWithCompatibleVersionOrCloseAndSelectNextDeadline(
        76,
        &conn,
        idle_deadline,
        .handshake,
        backend.backend(),
        &scratch,
        &[_]VersionCompatibility{},
    );

    try std.testing.expectEqual(@as(usize, 1), result.pending_work.idle_retired_count);
    try std.testing.expectEqual(@as(usize, 0), result.pending_work.close_retired_count);
    try std.testing.expectEqual(@as(usize, 0), result.pending_work.recovery_serviced_count);
    try std.testing.expectEqual(ConnectionState.closed, conn.connectionState());
    try std.testing.expectEqual(@as(usize, 0), result.backend.backend.connections_driven);
    try std.testing.expect(!backend.peer_sent);
    try std.testing.expectEqual(@as(?EndpointConnectionDeadline, null), result.backend.next_deadline);
    try std.testing.expectEqual(@as(usize, 0), lifecycle.routeCount());
    try std.testing.expectEqual(@as(usize, 0), lifecycle.recoveryTimerCount());
}

test "EndpointConnectionLifecycle single pending-work compatible close backend stops before next deadline on version error" {
    const Backend = struct {
        peer_transport_parameters: []const u8,
        peer_sent: bool = false,
        pulls: usize = 0,

        fn backend(self: *@This()) CryptoBackend {
            return .{
                .context = self,
                .receive = receive,
                .pull = pull,
                .pull_peer_transport_parameters = pullPeerTransportParameters,
            };
        }

        fn receive(_: *anyopaque, _: PacketNumberSpace, _: []const u8) Error!void {}

        fn pull(context: *anyopaque, _: PacketNumberSpace, out_buf: []u8) Error!?[]const u8 {
            const self: *@This() = @ptrCast(@alignCast(context));
            self.pulls += 1;
            if (out_buf.len == 0) return error.BufferTooSmall;
            out_buf[0] = 0;
            return out_buf[0..1];
        }

        fn pullPeerTransportParameters(context: *anyopaque, out_buf: []u8) Error!?[]const u8 {
            const self: *@This() = @ptrCast(@alignCast(context));
            if (self.peer_sent) return null;
            if (out_buf.len < self.peer_transport_parameters.len) return error.BufferTooSmall;
            @memcpy(out_buf[0..self.peer_transport_parameters.len], self.peer_transport_parameters);
            self.peer_sent = true;
            return out_buf[0..self.peer_transport_parameters.len];
        }
    };

    const client_versions = [_]packet.Version{ .v1, .v2 };
    const server_versions = [_]packet.Version{ .v2, .v1 };

    var peer_params_buf: [128]u8 = undefined;
    var peer_params_out = buffer.fixedWriter(&peer_params_buf);
    try transport_parameters.encode(peer_params_out.writer(), .{
        .initial_max_data = 4321,
        .version_information = .{
            .chosen_version = .v1,
            .available_versions = &client_versions,
        },
    });

    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();

    var conn = try Connection.init(std.testing.allocator, .server, .{
        .chosen_version = .v2,
        .available_versions = &server_versions,
        .initial_rtt_ms = 100,
    });
    defer conn.deinit();
    try conn.validatePeerAddress();
    try conn.confirmHandshake();
    _ = try conn.recordPacketSentInSpace(.application, 10, 100);
    try lifecycle.armRecoveryTimerFromConnection(77, &conn);
    const recovery_before = lifecycle.nextDeadline(77, &conn) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(EndpointConnectionDeadlineKind.recovery, recovery_before.kind);

    var backend = Backend{ .peer_transport_parameters = peer_params_out.getWritten() };
    var scratch: [256]u8 = undefined;
    try std.testing.expectError(
        error.InvalidPacket,
        lifecycle.processPendingWorkAndDriveCryptoBackendInSpaceWithCompatibleVersionOrCloseAndSelectNextDeadline(
            77,
            &conn,
            recovery_before.deadline_millis,
            .handshake,
            backend.backend(),
            &scratch,
            &[_]VersionCompatibility{},
        ),
    );

    try std.testing.expect(backend.peer_sent);
    try std.testing.expectEqual(@as(usize, 0), backend.pulls);
    try std.testing.expectEqual(ConnectionState.closing, conn.connectionState());
    try std.testing.expect(conn.pending_close != null);
    try std.testing.expectEqual(@as(u8, 1), conn.recovery_state.pto_count);
    try std.testing.expectEqual(@as(?i64, null), conn.closeDeadlineMillis());
    try std.testing.expectEqual(@as(?EndpointConnectionDeadline, null), lifecycle.nextDeadline(77, &conn));
}

test "EndpointConnectionLifecycle pending-work cross-connection poll waits for recovery service" {
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const server_dcid = [_]u8{ 0xca, 0xcb, 0xcc, 0xcd };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);

    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();

    var client = try Connection.init(std.testing.allocator, .client, .{
        .initial_rtt_ms = 100,
    });
    defer client.deinit();
    try client.confirmHandshake();
    try client.installOneRttTrafficSecrets(.{
        .local = secrets.client.secret,
        .peer = secrets.server.secret,
    });
    try client.sendPing();

    const pending_connections = [_]EndpointConnectionReceiveView{.{
        .connection_id = 201,
        .connection = &client,
    }};
    const poll_views = [_]EndpointConnectionPollView{.{
        .connection_id = 201,
        .connection = &client,
        .destination_connection_id = &server_dcid,
    }};

    const no_recovery = try lifecycle.processPendingWorkAcrossConnectionsAndPollDatagram(
        &pending_connections,
        10,
        &poll_views,
        .application,
    );
    try std.testing.expectEqual(@as(usize, 0), no_recovery.pending_work.recovery_serviced_count);
    try std.testing.expectEqual(@as(?EndpointPolledDatagramResult, null), no_recovery.datagram);
    try std.testing.expectEqual(@as(usize, 0), client.sentPacketCount(.application));

    const first = (try lifecycle.pollDatagram(201, &client, 20, .{
        .space = .application,
        .destination_connection_id = &server_dcid,
    })) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(first);
    const deadline = lifecycle.nextDeadline(201, &client) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(EndpointConnectionDeadlineKind.recovery, deadline.kind);

    const recovered = try lifecycle.processPendingWorkAcrossConnectionsAndPollDatagram(
        &pending_connections,
        deadline.deadline_millis,
        &poll_views,
        .application,
    );
    try std.testing.expectEqual(@as(usize, 0), recovered.pending_work.idle_retired_count);
    try std.testing.expectEqual(@as(usize, 0), recovered.pending_work.close_retired_count);
    try std.testing.expectEqual(@as(usize, 1), recovered.pending_work.recovery_serviced_count);
    const probe = recovered.datagram orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(probe.datagram);
    try std.testing.expectEqual(@as(u64, 201), probe.connection_id);
    try std.testing.expectEqual(@as(u8, 1), client.recovery_state.pto_count);
    try std.testing.expectEqual(@as(usize, 2), client.sentPacketCount(.application));
}

test "EndpointConnectionLifecycle pending-work cross-connection drain returns bounded recovery output" {
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const first_dcid = [_]u8{ 0xda, 0xdb, 0xdc, 0x01 };
    const second_dcid = [_]u8{ 0xda, 0xdb, 0xdc, 0x02 };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);

    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();

    var first = try Connection.init(std.testing.allocator, .client, .{
        .initial_rtt_ms = 100,
    });
    defer first.deinit();
    try first.confirmHandshake();
    try first.installOneRttTrafficSecrets(.{
        .local = secrets.client.secret,
        .peer = secrets.server.secret,
    });
    try first.sendPing();

    var second = try Connection.init(std.testing.allocator, .client, .{
        .initial_rtt_ms = 100,
    });
    defer second.deinit();
    try second.confirmHandshake();
    try second.installOneRttTrafficSecrets(.{
        .local = secrets.client.secret,
        .peer = secrets.server.secret,
    });
    try second.sendPing();

    const first_sent = (try lifecycle.pollDatagram(202, &first, 20, .{
        .space = .application,
        .destination_connection_id = &first_dcid,
    })) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(first_sent);
    const second_sent = (try lifecycle.pollDatagram(203, &second, 20, .{
        .space = .application,
        .destination_connection_id = &second_dcid,
    })) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(second_sent);

    const first_deadline = lifecycle.nextDeadline(202, &first) orelse return error.TestUnexpectedResult;
    const second_deadline = lifecycle.nextDeadline(203, &second) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(EndpointConnectionDeadlineKind.recovery, first_deadline.kind);
    try std.testing.expectEqual(EndpointConnectionDeadlineKind.recovery, second_deadline.kind);
    const now_millis = @max(first_deadline.deadline_millis, second_deadline.deadline_millis);

    const pending_connections = [_]EndpointConnectionReceiveView{
        .{ .connection_id = 202, .connection = &first },
        .{ .connection_id = 203, .connection = &second },
    };
    const poll_views = [_]EndpointConnectionPollView{
        .{
            .connection_id = 202,
            .connection = &first,
            .destination_connection_id = &first_dcid,
        },
        .{
            .connection_id = 203,
            .connection = &second,
            .destination_connection_id = &second_dcid,
        },
    };
    var out: [2]EndpointPolledDatagramResult = undefined;

    const drained = try lifecycle.processPendingWorkAcrossConnectionsAndDrainDatagrams(
        &pending_connections,
        now_millis,
        &poll_views,
        .application,
        &out,
    );
    try std.testing.expectEqual(@as(usize, 0), drained.pending_work.idle_retired_count);
    try std.testing.expectEqual(@as(usize, 0), drained.pending_work.close_retired_count);
    try std.testing.expectEqual(@as(usize, 2), drained.pending_work.recovery_serviced_count);
    try std.testing.expectEqual(@as(usize, 2), drained.drain.datagrams_written);
    try std.testing.expectEqual(@as(?Error, null), drained.drain.first_error);
    defer std.testing.allocator.free(out[0].datagram);
    defer std.testing.allocator.free(out[1].datagram);
    try std.testing.expectEqual(@as(u64, 202), out[0].connection_id);
    try std.testing.expectEqual(@as(u64, 203), out[1].connection_id);
    try std.testing.expectEqual(@as(u8, 1), first.recovery_state.pto_count);
    try std.testing.expectEqual(@as(u8, 1), second.recovery_state.pto_count);
    try std.testing.expectEqual(@as(usize, 2), first.sentPacketCount(.application));
    try std.testing.expectEqual(@as(usize, 2), second.sentPacketCount(.application));
}

test "EndpointConnectionLifecycle pending-work cross-connection poll keeps explicit zero RTT output" {
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const client_dcid = [_]u8{ 0x2a, 0x3a, 0x4a, 0x5a };
    const server_dcid = [_]u8{ 0xb2, 0xc2, 0xd2, 0xe2 };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);

    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();

    var client = try Connection.init(std.testing.allocator, .client, .{
        .initial_rtt_ms = 100,
    });
    defer client.deinit();
    try client.installZeroRttTrafficSecrets(.{ .local = secrets.client.secret });
    try client.confirmHandshake();

    const stream_id = try client.openStream();
    try client.sendOnStream(stream_id, "bye", false);
    try client.resetStream(stream_id, 71);
    const reset_frame: frame.ResetStreamFrame = .{
        .stream_id = stream_id,
        .application_error_code = 71,
        .final_size = 3,
    };

    const options: EndpointPollInstalledKeyDatagramOptions = .{
        .space = .zero_rtt,
        .destination_connection_id = &server_dcid,
        .source_connection_id = &client_dcid,
    };
    const first = (try lifecycle.pollDatagram(211, &client, 10, options)) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(first);
    try std.testing.expect(try protectedZeroRttContainsControlFrame(
        first,
        secrets.client,
        0,
        .{ .reset_stream = reset_frame },
    ));

    const deadline = lifecycle.nextDeadline(211, &client) orelse return error.TestUnexpectedResult;
    const timer = deadline.recovery orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(PacketNumberSpace.application, timer.space);

    const pending_connections = [_]EndpointConnectionReceiveView{.{
        .connection_id = 211,
        .connection = &client,
    }};
    const poll_views = [_]EndpointConnectionInstalledKeyPollView{.{
        .connection_id = 211,
        .connection = &client,
        .poll_options = options,
    }};

    const early = try lifecycle.processPendingWorkAcrossConnectionsAndPollDatagramWithInstalledKeyOptions(
        &pending_connections,
        timer.deadline_millis - 1,
        &poll_views,
    );
    try std.testing.expectEqual(@as(usize, 0), early.pending_work.recovery_serviced_count);
    try std.testing.expectEqual(@as(?EndpointPolledDatagramResult, null), early.datagram);
    try std.testing.expectEqual(@as(usize, 1), client.sentPacketCount(.application));

    const due = try lifecycle.processPendingWorkAcrossConnectionsAndPollDatagramWithInstalledKeyOptions(
        &pending_connections,
        timer.deadline_millis,
        &poll_views,
    );
    try std.testing.expectEqual(@as(usize, 1), due.pending_work.recovery_serviced_count);
    const probe = due.datagram orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(probe.datagram);
    try std.testing.expectEqual(@as(u64, 211), probe.connection_id);
    try std.testing.expectEqual(@as(usize, 2), client.sentPacketCount(.application));
    try std.testing.expectEqual(@as(u8, 1), client.recovery_state.pto_count);
    try std.testing.expect(try protectedZeroRttContainsControlFrame(
        probe.datagram,
        secrets.client,
        1,
        .{ .reset_stream = reset_frame },
    ));
}

