test "EndpointConnectionLifecycle emits protected Version Negotiation follow-up Initial" {
    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();

    const path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
    };
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const old_scid = [_]u8{ 0x11, 0x22, 0x33, 0x44 };
    const followup_scid = [_]u8{ 0x55, 0x66, 0x77, 0x88 };
    const initial_token = [_]u8{ 0xa1, 0xa2 };
    const initial_crypto = "vn follow-up protected initial";
    const client_versions = [_]packet.Version{ .v2, .v1 };
    const server_versions = [_]packet.Version{.v2};
    const secrets = try protection.deriveInitialSecrets(.v2, &original_dcid);

    var raw: [64]u8 = undefined;
    var out = buffer.fixedWriter(&raw);
    try packet.encodeVersionNegotiationPacket(out.writer(), .{
        .dcid = &old_scid,
        .scid = &original_dcid,
        .versions = &server_versions,
    });

    var old_client = try Connection.init(std.testing.allocator, .client, .{
        .chosen_version = .v1,
        .available_versions = &client_versions,
        .initial_rtt_ms = 100,
    });
    defer old_client.deinit();

    _ = try lifecycle.registerClientInitialSourceConnectionId(111, &old_scid, path, .{});
    _ = try old_client.recordPacketSentInSpace(.initial, 0, 1200);
    try lifecycle.armRecoveryTimerFromConnection(111, &old_client);

    var result = (try lifecycle.processVersionNegotiationProtectedInitialDatagram(
        111,
        112,
        &old_client,
        10,
        &original_dcid,
        &old_scid,
        &followup_scid,
        path,
        out.getWritten(),
        .{},
        &initial_token,
        initial_crypto,
    )) orelse return error.TestUnexpectedResult;
    defer result.handoff.followup_connection.deinit();
    defer std.testing.allocator.free(result.initial_datagram);

    try std.testing.expectEqual(packet.Version.v2, result.handoff.followup.version_negotiation.selected_version);
    try std.testing.expectEqual(packet.Version.v2, result.handoff.followup_connection.config.chosen_version);
    try std.testing.expectEqual(@as(u64, 112), result.handoff.followup.followup_route.connection_id);
    try std.testing.expectEqualStrings(&original_dcid, result.handoff.followup_connection.originalDestinationConnectionId().?);
    try std.testing.expectEqual(@as(usize, 1), result.handoff.followup_connection.sentPacketCount(.initial));
    try std.testing.expectEqual(result.initial_datagram.len, result.handoff.followup_connection.bytesInFlight(.initial));
    try std.testing.expect(result.initial_datagram.len >= min_initial_udp_datagram_len);
    try std.testing.expectEqual(@as(usize, 1), lifecycle.routeCount());
    try std.testing.expectEqual(@as(usize, 1), lifecycle.recoveryTimerCount());

    const info = try protection.peekProtectedLongPacketInfo(result.initial_datagram);
    try std.testing.expectEqual(packet.Version.v2, info.version);
    try std.testing.expectEqual(packet.PacketType.initial, info.packet_type);

    var server = try Connection.init(std.testing.allocator, .server, .{
        .chosen_version = .v2,
        .available_versions = &client_versions,
    });
    defer server.deinit();
    try server.processInitialProtectedDatagram(11, secrets.client, result.initial_datagram);
    try std.testing.expectEqualStrings(&original_dcid, server.originalDestinationConnectionId().?);
    try std.testing.expectEqualStrings(&followup_scid, server.peerInitialSourceConnectionId().?);
    var crypto_buf: [64]u8 = undefined;
    const recv_len = (try server.recvCryptoInSpace(.initial, &crypto_buf)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqualStrings(initial_crypto, crypto_buf[0..recv_len]);

    const server_scid = [_]u8{ 0xa1, 0xa2, 0xa3, 0xa4 };
    try server.validatePeerAddress();
    try server.sendCryptoInSpace(.initial, "vn server initial");
    const server_initial = (try server.pollInitialProtectedDatagram(
        12,
        &followup_scid,
        &server_scid,
        &[_]u8{},
        secrets.server,
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(server_initial);
    try result.handoff.followup_connection.processInitialProtectedDatagram(13, secrets.server, server_initial);
    try std.testing.expectEqualStrings(&server_scid, result.handoff.followup_connection.peerInitialSourceConnectionId().?);
    var server_tp_buf: [256]u8 = undefined;
    const server_tp = try server.encodeLocalTransportParameters(&server_tp_buf);
    try result.handoff.followup_connection.applyPeerTransportParameterBytes(server_tp);
    const peer_version_information = result.handoff.followup_connection.peerVersionInformation() orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(packet.Version.v2, peer_version_information.chosen_version);
}

test "EndpointConnectionLifecycle processes accepted protected Initial after authentication" {
    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();

    const path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
    };
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const client_scid = [_]u8{ 0x11, 0x22, 0x33, 0x44 };
    const server_scid = [_]u8{ 0xaa, 0xbb, 0xcc, 0xdd };
    const reset_token = [_]u8{ 0x40, 0x41, 0x42, 0x43, 0x44, 0x45, 0x46, 0x47, 0x48, 0x49, 0x4a, 0x4b, 0x4c, 0x4d, 0x4e, 0x4f };
    const reset_prefix = [_]u8{ 0x40, 0x12, 0x34, 0x56, 0x78, 0x9a, 0xbc, 0xde };
    const supported_versions = [_]packet.Version{ .v1, .v2 };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);

    var client = try Connection.init(std.testing.allocator, .client, .{});
    defer client.deinit();
    try client.sendCryptoInSpace(.initial, "accepted protected initial");
    const initial = (try client.pollInitialProtectedDatagram(
        10,
        &original_dcid,
        &client_scid,
        &[_]u8{},
        secrets.client,
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(initial);

    var action_buf: [256]u8 = undefined;
    const action = try lifecycle.handleDatagramWithVersionNegotiation(
        &action_buf,
        path,
        initial,
        &reset_prefix,
        &supported_versions,
    );
    const accept = switch (action) {
        .accept_initial => |initial_accept| initial_accept,
        else => return error.TestUnexpectedResult,
    };

    var server = try Connection.init(std.testing.allocator, .server, .{});
    defer server.deinit();
    const result = try lifecycle.processAcceptedProtectedInitialDatagram(
        201,
        &server,
        11,
        accept,
        &server_scid,
        initial,
        .{
            .active_migration_disabled = true,
            .stateless_reset_token = reset_token,
        },
    );

    try std.testing.expectEqual(@as(usize, 1), result.processed_packets);
    try std.testing.expectEqual(packet.Version.v1, result.initial_accept.version);
    try std.testing.expectEqual(@as(u64, 201), result.accepted_routes.original_destination_route.connection_id);
    try std.testing.expectEqual(@as(u64, 201), result.accepted_routes.server_source_route.connection_id);
    try std.testing.expectEqual(@as(usize, 2), lifecycle.routeCount());
    try std.testing.expectEqual(@as(usize, 1), lifecycle.statelessResetTokenCount());
    try std.testing.expectEqual(@as(usize, 0), lifecycle.recoveryTimerCount());
    try std.testing.expectEqual(@as(?usize, initial.len * anti_amplification_multiplier), server.antiAmplificationLimitRemaining());

    const retransmit_route = try lifecycle.routeDatagram(path, initial);
    try std.testing.expectEqual(@as(u64, 201), retransmit_route.connection_id);
    try std.testing.expectEqualSlices(u8, &original_dcid, retransmit_route.destination_connection_id.asSlice());
    const short_to_server = [_]u8{ 0x40, 0xaa, 0xbb, 0xcc, 0xdd, 0x00 };
    const short_route = try lifecycle.routeDatagram(path, &short_to_server);
    try std.testing.expectEqual(@as(u64, 201), short_route.connection_id);
    try std.testing.expectEqualSlices(u8, &server_scid, short_route.destination_connection_id.asSlice());

    try std.testing.expectEqualStrings(&original_dcid, server.originalDestinationConnectionId().?);
    try std.testing.expectEqualStrings(&client_scid, server.peerInitialSourceConnectionId().?);
    try std.testing.expectEqual(@as(?u64, 0), server.pendingAckLargest(.initial));
    var crypto_buf: [64]u8 = undefined;
    const recv_len = (try server.recvCryptoInSpace(.initial, &crypto_buf)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqualStrings("accepted protected initial", crypto_buf[0..recv_len]);
}

