    try std.testing.expectEqual(@as(?u64, null), server.pendingAckLargest(.initial));
    try std.testing.expectEqual(@as(?[]const u8, null), server.originalDestinationConnectionId());
}

test "EndpointConnectionLifecycle does not hand off connection for ignored Version Negotiation" {
    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();

    const path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
    };
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const old_scid = [_]u8{ 0x11, 0x22, 0x33, 0x44 };
    const followup_scid = [_]u8{ 0x55, 0x66, 0x77, 0x88 };
    const client_versions = [_]packet.Version{ .v2, .v1 };
    const server_versions = [_]packet.Version{ .v2, .v1 };
    const old_short = [_]u8{ 0x40, 0x11, 0x22, 0x33, 0x44 };
    const followup_short = [_]u8{ 0x40, 0x55, 0x66, 0x77, 0x88 };

    var raw: [80]u8 = undefined;
    var out = buffer.fixedWriter(&raw);
    try packet.encodeVersionNegotiationPacket(out.writer(), .{
        .dcid = &old_scid,
        .scid = &original_dcid,
        .versions = &server_versions,
    });

    var client = try Connection.init(std.testing.allocator, .client, .{
        .chosen_version = .v1,
        .available_versions = &client_versions,
    });
    defer client.deinit();

    _ = try lifecycle.registerClientInitialSourceConnectionId(109, &old_scid, path, .{});
    _ = try client.recordPacketSentInSpace(.initial, 0, 1200);
    try lifecycle.armRecoveryTimerFromConnection(109, &client);

    try std.testing.expect((try lifecycle.processVersionNegotiationHandoffDatagram(
        109,
        110,
        &client,
        10,
        &original_dcid,
        &old_scid,
        &followup_scid,
        path,
        out.getWritten(),
        .{},
    )) == null);
    try std.testing.expectEqual(@as(?packet.Version, null), client.versionNegotiationSelectedVersion());
    try std.testing.expectEqual(@as(usize, 1), lifecycle.routeCount());
    try std.testing.expectEqual(@as(usize, 1), lifecycle.recoveryTimerCount());
    const old_route = try lifecycle.routeDatagram(path, &old_short);
    try std.testing.expectEqual(@as(u64, 109), old_route.connection_id);
    try std.testing.expectError(error.UnknownConnectionId, lifecycle.routeDatagram(path, &followup_short));
}

test "EndpointConnectionLifecycle updates caller-validated route path" {
    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();

    const old_path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
    };
    const new_path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_001),
    };
    const dcid = [_]u8{ 0xaa, 0xbb, 0xcc, 0xdd };
    const short_datagram = [_]u8{ 0x40, 0xaa, 0xbb, 0xcc, 0xdd, 0x00 };

    try lifecycle.registerConnectionId(77, &dcid, old_path, .{ .sequence_number = 3 });
    const old_route = try lifecycle.routeDatagram(old_path, &short_datagram);
    try std.testing.expectEqual(@as(u64, 77), old_route.connection_id);
    try std.testing.expectEqual(@as(?u64, 3), old_route.sequence_number);
    try std.testing.expect(!old_route.path_changed);

    const migration_route = try lifecycle.routeDatagram(new_path, &short_datagram);
    try std.testing.expectEqual(@as(u64, 77), migration_route.connection_id);
    try std.testing.expect(migration_route.path_changed);

    const updated_route = try lifecycle.updateRoutePath(&dcid, old_path, new_path);
    try std.testing.expectEqual(@as(u64, 77), updated_route.connection_id);
    try std.testing.expectEqual(@as(?u64, 3), updated_route.sequence_number);
    try std.testing.expect(!updated_route.path_changed);

    const confirmed_route = try lifecycle.routeDatagram(new_path, &short_datagram);
    try std.testing.expectEqual(@as(u64, 77), confirmed_route.connection_id);
    try std.testing.expect(!confirmed_route.path_changed);
    try std.testing.expectError(error.PathMismatch, lifecycle.updateRoutePath(&dcid, old_path, new_path));
}

test "EndpointConnectionLifecycle updates route path after protected PATH_RESPONSE validation" {
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const client_dcid = [_]u8{ 0x10, 0x20, 0x30, 0x40 };
    const server_dcid = [_]u8{ 0xaa, 0xbb, 0xcc, 0xdd };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);

    const old_path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
    };
    const new_path = endpoint.Udp4Tuple{
        .local = old_path.local,
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_001),
    };

    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();
    try lifecycle.registerConnectionId(88, &server_dcid, old_path, .{});

    var server = try Connection.init(std.testing.allocator, .server, .{});
    defer server.deinit();
    var client = try Connection.init(std.testing.allocator, .client, .{});
    defer client.deinit();
    try server.validatePeerAddress();

    try client.sendPing();
    const migrated_ping = (try client.pollProtectedShortDatagram(1, &server_dcid, secrets.client)) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(migrated_ping);
    const ping_result = try lifecycle.processRoutedProtectedShortDatagramAndUpdatePath(
        88,
        &server,
        new_path,
        2,
        secrets.client,
        migrated_ping,
    );
    try std.testing.expect(ping_result.route.path_changed);
    try std.testing.expect(ping_result.updated_route == null);
    try std.testing.expectEqual(@as(usize, 0), server.outstandingPathChallengeCount());
    try std.testing.expect((try lifecycle.routeDatagram(new_path, migrated_ping)).path_changed);

    const challenge_data = [_]u8{ 0x44, 0x55, 0x66, 0x77, 0x88, 0x99, 0xaa, 0xbb };
    try server.sendPathChallenge(challenge_data);
    const challenge = (try server.pollProtectedShortDatagram(3, &client_dcid, secrets.server)) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(challenge);
    try std.testing.expectEqual(@as(usize, 1), server.outstandingPathChallengeCount());
    try client.processProtectedShortDatagram(4, secrets.server, client_dcid.len, challenge);

    const response = (try client.pollProtectedShortDatagram(5, &server_dcid, secrets.client)) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(response);
    const validation_result = try lifecycle.processRoutedProtectedShortDatagramAndUpdatePath(
        88,
        &server,
        new_path,
        6,
        secrets.client,
        response,
    );
    try std.testing.expect(validation_result.route.path_changed);
    const updated_route = validation_result.updated_route orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(@as(u64, 88), updated_route.connection_id);
    try std.testing.expect(!updated_route.path_changed);
    try std.testing.expectEqual(@as(usize, 0), server.outstandingPathChallengeCount());

    const confirmed_route = try lifecycle.routeDatagram(new_path, response);
    try std.testing.expectEqual(@as(u64, 88), confirmed_route.connection_id);
    try std.testing.expect(!confirmed_route.path_changed);
}

