    try std.testing.expectEqual(@as(u64, 72), (try lifecycle.routeDatagram(path1, &short_datagram)).connection_id);
    try std.testing.expect(!try lifecycle.retireConnectionIdOnPath(&empty_cid, path0));
}

test "EndpointConnectionLifecycle commits preferred address migration" {
    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();

    const current_path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
    };
    const preferred_path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4434),
    };
    const stray_path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4435),
    };
    const current_cid = [_]u8{ 0x30, 0x31, 0x32, 0x33 };
    const preferred_cid = [_]u8{ 0x34, 0x35, 0x36, 0x37 };
    const preferred_token = [_]u8{ 0x44, 0x45, 0x46, 0x47, 0x48, 0x49, 0x4a, 0x4b, 0x4c, 0x4d, 0x4e, 0x4f, 0x50, 0x51, 0x52, 0x53 };
    const current_datagram = [_]u8{ 0x40, 0x30, 0x31, 0x32, 0x33, 0x01 };
    const preferred_datagram = [_]u8{ 0x40, 0x34, 0x35, 0x36, 0x37, 0x01 };

    try lifecycle.registerConnectionId(81, &current_cid, current_path, .{
        .active_migration_disabled = true,
    });
    try std.testing.expectEqual(@as(u64, 81), (try lifecycle.routeDatagram(current_path, &current_datagram)).connection_id);

    const migrated = try lifecycle.commitPreferredAddressMigration(
        &current_cid,
        current_path,
        &preferred_cid,
        preferred_path,
        preferred_token,
    );
    try std.testing.expectEqual(@as(u64, 81), migrated.connection_id);
    try std.testing.expectEqualSlices(u8, &preferred_cid, migrated.destination_connection_id.asSlice());
    try std.testing.expectEqual(@as(usize, 1), lifecycle.routeCount());
    try std.testing.expectError(error.UnknownConnectionId, lifecycle.routeDatagram(current_path, &current_datagram));
    try std.testing.expectEqual(@as(u64, 81), (try lifecycle.routeDatagram(preferred_path, &preferred_datagram)).connection_id);
    try std.testing.expectError(error.ActiveMigrationDisabled, lifecycle.routeDatagram(stray_path, &preferred_datagram));
    try std.testing.expectEqual(@as(?[packet.stateless_reset_token_len]u8, null), try lifecycle.statelessResetTokenForDatagram(preferred_path, &preferred_datagram));

    const retired = lifecycle.retireConnection(81);
    try std.testing.expectEqual(@as(usize, 1), retired.routes_retired);
    const retained = (try lifecycle.statelessResetTokenForDatagram(preferred_path, &preferred_datagram)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqualSlices(u8, &preferred_token, &retained);
}

test "EndpointConnectionLifecycle registers replacement connection IDs" {
    const cid0 = [_]u8{ 0xc0, 0xff, 0xee, 0x00 };
    const cid1 = [_]u8{ 0xc0, 0xff, 0xee, 0x01 };
    const token0 = [_]u8{0x42} ** packet.stateless_reset_token_len;
    const token1 = [_]u8{0x24} ** packet.stateless_reset_token_len;
    const path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
    };
    const datagram0 = [_]u8{ 0x40, 0xc0, 0xff, 0xee, 0x00, 0x01 };
    const datagram1 = [_]u8{ 0x40, 0xc0, 0xff, 0xee, 0x01, 0x01 };

    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();
    var conn = try Connection.init(std.testing.allocator, .server, .{});
    defer conn.deinit();

    const issued0 = try lifecycle.issueConnectionIdRoute(51, &conn, &cid0, path, token0, 0, .{});
    try std.testing.expectEqual(@as(u64, 0), issued0.sequence_number);
    try std.testing.expectEqual(@as(u64, 0), issued0.retire_prior_to);
    try std.testing.expectEqual(@as(usize, 0), issued0.retired_count);
    try std.testing.expectEqual(@as(usize, 1), conn.pendingNewConnectionIdCount());
    try std.testing.expectEqual(@as(usize, 1), lifecycle.routeCount());
    try std.testing.expectEqual(@as(usize, 1), lifecycle.statelessResetTokenCount());

    const replacement = try lifecycle.issueConnectionIdRoute(51, &conn, &cid1, path, token1, 1, .{});
    try std.testing.expectEqual(@as(u64, 1), replacement.sequence_number);
    try std.testing.expectEqual(@as(u64, 1), replacement.retire_prior_to);
    try std.testing.expectEqual(@as(usize, 1), replacement.retired_count);
    try std.testing.expectEqual(@as(usize, 2), conn.pendingNewConnectionIdCount());
    try std.testing.expectEqual(@as(usize, 1), lifecycle.routeCount());
    try std.testing.expectEqual(@as(usize, 2), lifecycle.statelessResetTokenCount());

    try std.testing.expectError(error.UnknownConnectionId, lifecycle.routeDatagram(path, &datagram0));
    const retired_token0 = (try lifecycle.statelessResetTokenForDatagram(path, &datagram0)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqualSlices(u8, &token0, &retired_token0);

    const active_route = try lifecycle.routeDatagram(path, &datagram1);
    try std.testing.expectEqual(@as(u64, 51), active_route.connection_id);
    try std.testing.expectEqual(@as(?u64, 1), active_route.sequence_number);
    try std.testing.expectEqual(@as(?[packet.stateless_reset_token_len]u8, null), try lifecycle.statelessResetTokenForDatagram(path, &datagram1));
}

test "EndpointConnectionLifecycle rolls back issued connection ID route failures" {
    const occupied_cid = [_]u8{ 0xc0, 0xff, 0xee, 0x00 };
    const rollback_cid = [_]u8{ 0xc0, 0xff, 0xee, 0x01 };
    const committed_cid = [_]u8{ 0xc0, 0xff, 0xee, 0x02 };
    const occupied_token = [_]u8{0x42} ** packet.stateless_reset_token_len;
    const rollback_token = [_]u8{0x24} ** packet.stateless_reset_token_len;
    const committed_token = [_]u8{0x18} ** packet.stateless_reset_token_len;
    const path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
    };
    const committed_datagram = [_]u8{ 0x40, 0xc0, 0xff, 0xee, 0x02, 0x01 };

    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();
    var conn = try Connection.init(std.testing.allocator, .server, .{});
    defer conn.deinit();

    try lifecycle.registerConnectionId(51, &occupied_cid, path, .{
        .sequence_number = 0,
        .stateless_reset_token = occupied_token,
    });

    try std.testing.expectError(
        error.DuplicateConnectionId,
        lifecycle.issueConnectionIdRoute(51, &conn, &rollback_cid, path, rollback_token, 0, .{}),
    );
    try std.testing.expectEqual(@as(u64, 0), conn.localConnectionIdCount());
    try std.testing.expectEqual(@as(usize, 0), conn.pendingNewConnectionIdCount());
    try std.testing.expectEqual(@as(usize, 1), lifecycle.routeCount());
    try std.testing.expectEqual(@as(usize, 1), lifecycle.statelessResetTokenCount());

    try std.testing.expect(try lifecycle.retireConnectionIdOnPath(&occupied_cid, path));
    const committed = try lifecycle.issueConnectionIdRoute(51, &conn, &committed_cid, path, committed_token, 0, .{});
    try std.testing.expectEqual(@as(u64, 0), committed.sequence_number);
    try std.testing.expectEqual(@as(u64, 1), conn.localConnectionIdCount());
    try std.testing.expectEqual(@as(usize, 1), conn.pendingNewConnectionIdCount());
    const route = try lifecycle.routeDatagram(path, &committed_datagram);
    try std.testing.expectEqual(@as(?u64, 0), route.sequence_number);
}

test "EndpointConnectionLifecycle mirrors ECN validation by UDP path" {
    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();

    const old_path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
    };
    const migrated_path = endpoint.Udp4Tuple{
        .local = old_path.local,
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_001),
    };

    try std.testing.expectEqual(endpoint.EcnPathValidationState.unknown, lifecycle.ecnPathState(old_path));
    try std.testing.expect(lifecycle.mayUseEctOnPath(old_path));

    var validated = try Connection.init(std.testing.allocator, .client, .{});
    defer validated.deinit();

    _ = try validated.recordEcnPacketSentInSpace(.application, 10, 100, .ect0);
    try validated.receiveAckEcnInSpace(.application, 60, .{
        .ack = .{
            .largest_acknowledged = 0,
            .ack_delay = 0,
            .first_ack_range = 0,
        },
        .ecn_counts = .{
            .ect0_count = 1,
            .ect1_count = 0,
            .ecn_ce_count = 0,
        },
    });
    try std.testing.expectEqual(
        endpoint.EcnPathValidationState.capable,
        try lifecycle.refreshEcnPathStateFromConnection(old_path, &validated, .application),
    );
    try std.testing.expectEqual(endpoint.EcnPathValidationState.capable, lifecycle.ecnPathState(old_path));
    try std.testing.expectEqual(endpoint.EcnPathValidationState.unknown, lifecycle.ecnPathState(migrated_path));
    try std.testing.expect(lifecycle.mayUseEctOnPath(migrated_path));

    var failed = try Connection.init(std.testing.allocator, .client, .{});
    defer failed.deinit();

    _ = try failed.recordEcnPacketSentInSpace(.application, 10, 100, .ect0);
    try failed.receiveAckInSpace(.application, 60, .{
        .largest_acknowledged = 0,
        .ack_delay = 0,
        .first_ack_range = 0,
    });
    try std.testing.expectEqual(
        endpoint.EcnPathValidationState.failed,
        try lifecycle.refreshEcnPathStateFromConnection(migrated_path, &failed, .application),
    );
    try std.testing.expectEqual(endpoint.EcnPathValidationState.capable, lifecycle.ecnPathState(old_path));
    try std.testing.expectEqual(endpoint.EcnPathValidationState.failed, lifecycle.ecnPathState(migrated_path));
    try std.testing.expect(!lifecycle.mayUseEctOnPath(migrated_path));
}

test "EndpointConnectionLifecycle resets spin bit after route path update" {
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const server_dcid = [_]u8{ 0xaa, 0xbb, 0xcc, 0xdd };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);

    const old_path = endpoint.Udp4Tuple{
        .local = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433),
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000),
    };
    const new_path = endpoint.Udp4Tuple{
        .local = old_path.local,
        .remote = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_001),
    };

    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();
    try lifecycle.registerConnectionId(51, &server_dcid, old_path, .{});

    var client = try Connection.init(std.testing.allocator, .client, .{ .enable_spin_bit = true });
    defer client.deinit();
    var server = try Connection.init(std.testing.allocator, .server, .{ .enable_spin_bit = true });
    defer server.deinit();
    try server.validatePeerAddress();

    try client.sendPing();
    const first_ping = (try client.pollProtectedShortDatagram(10, &server_dcid, secrets.client)) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(first_ping);
    try std.testing.expect(!try protection.peekShortPacketSpinBit(first_ping));
    try server.processProtectedShortDatagram(11, secrets.client, server_dcid.len, first_ping);

    const first_ack = (try server.pollProtectedShortDatagram(12, &original_dcid, secrets.server)) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(first_ack);
    try client.processProtectedShortDatagram(13, secrets.server, original_dcid.len, first_ack);
    try std.testing.expect(client.nextOutgoingSpinBit());

    try client.sendPing();
    const second_ping = (try client.pollProtectedShortDatagram(14, &server_dcid, secrets.client)) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(second_ping);
    try std.testing.expect(try protection.peekShortPacketSpinBit(second_ping));

    const migrated_route = try lifecycle.routeDatagram(new_path, second_ping);
    try std.testing.expectEqual(@as(u64, 51), migrated_route.connection_id);
    try std.testing.expect(migrated_route.path_changed);
    try server.processProtectedShortDatagram(15, secrets.client, server_dcid.len, second_ping);
    try std.testing.expect(server.nextOutgoingSpinBit());

    const updated_route = try lifecycle.updateRoutePathAndResetSpinBit(&server_dcid, old_path, new_path, &server);
    try std.testing.expectEqual(@as(u64, 51), updated_route.connection_id);
    try std.testing.expect(!updated_route.path_changed);
    try std.testing.expect(!server.nextOutgoingSpinBit());

    const confirmed_route = try lifecycle.routeDatagram(new_path, second_ping);
    try std.testing.expectEqual(@as(u64, 51), confirmed_route.connection_id);
    try std.testing.expect(!confirmed_route.path_changed);
}

test "EndpointConnectionLifecycle refreshes protected long timer lifecycle" {
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const client_scid = [_]u8{ 0x11, 0x22, 0x33, 0x44 };
    const server_scid = [_]u8{ 0xaa, 0xbb, 0xcc, 0xdd };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);

    var client_lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer client_lifecycle.deinit();
    var server_lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer server_lifecycle.deinit();

    var client = try Connection.init(std.testing.allocator, .client, .{
        .initial_rtt_ms = 100,
    });
    defer client.deinit();
    var server = try Connection.init(std.testing.allocator, .server, .{
        .initial_rtt_ms = 100,
    });
    defer server.deinit();
    try server.validatePeerAddress();

    const client_addr = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_000);
    const server_addr = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433);
    const server_receive_path = endpoint.Udp4Tuple{
        .local = server_addr,
        .remote = client_addr,
    };
    const client_receive_path = endpoint.Udp4Tuple{
        .local = client_addr,
        .remote = server_addr,
    };
    const client_connection_id: u64 = 10;
    const server_connection_id: u64 = 20;

    try client_lifecycle.registerConnectionId(client_connection_id, &client_scid, client_receive_path, .{
        .sequence_number = 0,
    });
    try server_lifecycle.registerConnectionId(server_connection_id, &original_dcid, server_receive_path, .{
        .sequence_number = 0,
    });

    try client.sendCryptoInSpace(.initial, "client initial");
    const initial = (try client_lifecycle.pollProtectedLongDatagram(
        client_connection_id,
        &client,
        10,
        &original_dcid,
        &client_scid,
        &[_]u8{},
        .{ .initial = secrets.client },
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(initial);
    try std.testing.expectEqual(@as(usize, 1), client_lifecycle.recoveryTimerCount());
    try std.testing.expectEqual(@as(usize, 1), client.sentPacketCount(.initial));

    try std.testing.expectError(error.InvalidPacket, server_lifecycle.processRoutedProtectedLongDatagram(
        client_connection_id,
        &server,
        server_receive_path,
        11,
        .{ .initial = secrets.client },
        initial,
    ));
    const server_result = try server_lifecycle.processRoutedProtectedLongDatagram(
        server_connection_id,
        &server,
        server_receive_path,
        11,
        .{ .initial = secrets.client },
        initial,
    );
    try std.testing.expectEqual(server_connection_id, server_result.route.connection_id);
    try std.testing.expectEqualSlices(u8, &original_dcid, server_result.route.destination_connection_id.asSlice());
    try std.testing.expectEqual(@as(usize, 1), server_result.processed_packets);
    try std.testing.expectEqual(@as(?u64, 0), server.pendingAckLargest(.initial));
    try std.testing.expectEqual(@as(usize, 0), server_lifecycle.recoveryTimerCount());

    var crypto_buf: [32]u8 = undefined;
    const recv_len = (try server.recvCryptoInSpace(.initial, &crypto_buf)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqualStrings("client initial", crypto_buf[0..recv_len]);

    const ack = (try server_lifecycle.pollProtectedLongDatagram(
        server_connection_id,
        &server,
        12,
        &client_scid,
        &server_scid,
        &[_]u8{},
        .{ .initial = secrets.server },
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(ack);
    try std.testing.expectEqual(@as(?u64, null), server.pendingAckLargest(.initial));
    try std.testing.expectEqual(@as(usize, 0), server_lifecycle.recoveryTimerCount());

    try std.testing.expectError(error.InvalidPacket, client_lifecycle.processRoutedProtectedLongDatagram(
        server_connection_id,
        &client,
        client_receive_path,
        13,
        .{ .initial = secrets.server },
        ack,
    ));
    const client_result = try client_lifecycle.processRoutedProtectedLongDatagram(
        client_connection_id,
        &client,
        client_receive_path,
        13,
        .{ .initial = secrets.server },
        ack,
    );
    try std.testing.expectEqual(client_connection_id, client_result.route.connection_id);
    try std.testing.expectEqualSlices(u8, &client_scid, client_result.route.destination_connection_id.asSlice());
    try std.testing.expectEqual(@as(usize, 1), client_result.processed_packets);
    try std.testing.expectEqual(@as(usize, 0), client.sentPacketCount(.initial));
    try std.testing.expectEqual(@as(usize, 0), client.bytesInFlight(.initial));
    try std.testing.expectEqual(@as(usize, 1), client_lifecycle.recoveryTimerCount());
    const anti_deadlock_timer = client_lifecycle.earliestRecoveryDeadline() orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(client_connection_id, anti_deadlock_timer.connection_id);
    try std.testing.expectEqual(PacketNumberSpace.initial, anti_deadlock_timer.timer.space);
    try std.testing.expectEqual(LossDetectionTimerKind.pto, anti_deadlock_timer.timer.kind);
}

