    try server.sendCryptoInSpace(.handshake, "caller handshake");
    const handshake = (try server_lifecycle.pollProtectedLongCryptoDatagramInSpace(
        server_connection_id,
        &server,
        .handshake,
        10,
        &client_scid,
        &server_scid,
        &[_]u8{},
        secrets.server,
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(handshake);
    try std.testing.expectEqual(@as(usize, 1), server_lifecycle.recoveryTimerCount());
    try std.testing.expectEqual(@as(usize, 1), server.sentPacketCount(.handshake));

    try std.testing.expectError(error.InvalidPacket, client_lifecycle.processRoutedProtectedLongDatagramInSpace(
        server_connection_id,
        &client,
        .handshake,
        client_receive_path,
        11,
        secrets.server,
        handshake,
    ));
    const client_route = try client_lifecycle.processRoutedProtectedLongDatagramInSpace(
        client_connection_id,
        &client,
        .handshake,
        client_receive_path,
        11,
        secrets.server,
        handshake,
    );
    try std.testing.expectEqual(client_connection_id, client_route.connection_id);
    try std.testing.expectEqualSlices(u8, &client_scid, client_route.destination_connection_id.asSlice());
    try std.testing.expectEqual(@as(?u64, 0), client.pendingAckLargest(.handshake));
    try std.testing.expectEqual(@as(usize, 0), client_lifecycle.recoveryTimerCount());

    var crypto_buf: [32]u8 = undefined;
    const recv_len = (try client.recvCryptoInSpace(.handshake, &crypto_buf)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqualStrings("caller handshake", crypto_buf[0..recv_len]);

    const ack = (try client_lifecycle.pollProtectedLongDatagram(
        client_connection_id,
        &client,
        12,
        &server_scid,
        &client_scid,
        &[_]u8{},
        .{ .handshake = secrets.client },
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(ack);
    try std.testing.expectEqual(@as(?u64, null), client.pendingAckLargest(.handshake));
    try std.testing.expectEqual(@as(usize, 0), client_lifecycle.recoveryTimerCount());

    try std.testing.expectError(error.InvalidPacket, server_lifecycle.processRoutedProtectedLongDatagramInSpace(
        client_connection_id,
        &server,
        .handshake,
        server_receive_path,
        13,
        secrets.client,
        ack,
    ));
    const server_route = try server_lifecycle.processRoutedProtectedLongDatagramInSpace(
        server_connection_id,
        &server,
        .handshake,
        server_receive_path,
        13,
        secrets.client,
        ack,
    );
    try std.testing.expectEqual(server_connection_id, server_route.connection_id);
    try std.testing.expectEqualSlices(u8, &server_scid, server_route.destination_connection_id.asSlice());
    try std.testing.expectEqual(@as(usize, 0), server.sentPacketCount(.handshake));
    try std.testing.expectEqual(@as(usize, 0), server.bytesInFlight(.handshake));
    try std.testing.expectEqual(@as(usize, 0), server_lifecycle.recoveryTimerCount());
    try std.testing.expectEqual(@as(?EndpointLossDetectionTimerDeadline, null), server_lifecycle.earliestRecoveryDeadline());
}

test "EndpointConnectionLifecycle processes long datagram in space and polls output" {
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const client_scid = [_]u8{ 0x11, 0x22, 0x33, 0x44 };
    const server_scid = [_]u8{ 0xaa, 0xbb, 0xcc, 0xdd };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);

    var lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
    defer lifecycle.deinit();
    var client = try Connection.init(std.testing.allocator, .client, .{});
    defer client.deinit();
    var server = try Connection.init(std.testing.allocator, .server, .{});
    defer server.deinit();
    try server.validatePeerAddress();

    try client.sendCryptoInSpace(.handshake, "long poll input");
    const client_datagram = (try client.pollProtectedLongCryptoDatagramInSpace(
        .handshake,
        10,
        &server_scid,
        &client_scid,
        &[_]u8{},
        secrets.client,
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(client_datagram);
    try std.testing.expectEqual(@as(usize, 1), client.sentPacketCount(.handshake));

    const result = (try lifecycle.processProtectedLongDatagramInSpaceAndPollDatagram(
