    try server.confirmHandshake();

    const client_addr = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 50_013);
    const server_addr = endpoint.Udp4Address.init(.{ 127, 0, 0, 1 }, 4433);
