        .packet_type = .zero_rtt,
        .token = &[_]u8{},
        .packet_number = 0,
        .payload_length = 0,
    }, try packet.encodePacketNumberForHeader(0, null), secrets.client, &plaintext);
    defer std.testing.allocator.free(invalid_zero_rtt);

