    try std.testing.expectEqual(@as(usize, 0), server_lifecycle.recoveryTimerCount());
    try std.testing.expectEqual(@as(?EndpointLossDetectionTimerDeadline, null), server_lifecycle.earliestRecoveryDeadline());
}

