test "EndpointConnectionLifecycle installed-key zero RTT OrClose stops before short poll" {
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const client_dcid = [_]u8{ 0x15, 0x25, 0x35, 0x45 };
