    try transport_parameters.encode(peer_params_out.writer(), .{
        .initial_max_data = 12_864,
        .version_information = .{
            .chosen_version = .v1,
            .available_versions = &client_versions,
        },
    });

    var client_lifecycle = EndpointConnectionLifecycle.init(std.testing.allocator);
