    try client.resetStream(stream_id, 19);
    const reset_frame: frame.ResetStreamFrame = .{
        .stream_id = stream_id,
        .application_error_code = 19,
        .final_size = 3,
    };

    const first = (try lifecycle.pollProtectedZeroRttDatagramWithInstalledKeys(
