test "processInitialProtectedDatagram rejects tampered packet without state changes" {
    const dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const scid = [_]u8{ 0x11, 0x22, 0x33, 0x44 };
