    try std.testing.expectEqual(@as(?u64, 1), client.localOneRttKeyUpdateCount());
    try std.testing.expectEqual(@as(?bool, false), client.localOneRttRetainsKeyGeneration(0));
    try std.testing.expectEqual(@as(?bool, true), client.localOneRttRetainsKeyGeneration(1));
    try std.testing.expectEqual(@as(?bool, true), client.localOneRttRetainsKeyGeneration(2));
    try std.testing.expectEqual(@as(?u64, 0), client.pendingOneRttKeyUpdateAckThreshold());
    try std.testing.expectError(error.InvalidPacket, client.initiateOneRttKeyUpdate());

    try client.sendPing();
    const ping = (try client.pollProtectedShortDatagramWithInstalledKeys(
        10,
        &server_dcid,
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(ping);
    try server.processProtectedShortDatagramWithInstalledKeys(11, server_dcid.len, ping);
    try std.testing.expectEqual(@as(?u64, 1), server.peerOneRttKeyUpdateCount());
    try std.testing.expectEqual(@as(?bool, false), server.peerOneRttRetainsKeyGeneration(0));
    try std.testing.expectEqual(@as(?bool, true), server.peerOneRttRetainsKeyGeneration(1));
    try std.testing.expectEqual(@as(?bool, true), server.peerOneRttRetainsKeyGeneration(2));
    const ack = (try server.pollProtectedShortDatagramWithInstalledKeys(
        12,
        &client_dcid,
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(ack);
    try client.processProtectedShortDatagramWithInstalledKeys(13, client_dcid.len, ack);
    try std.testing.expectEqual(@as(?u64, null), client.pendingOneRttKeyUpdateAckThreshold());

    try client.initiateOneRttKeyUpdate();
    try std.testing.expectEqual(@as(?bool, false), client.localOneRttKeyPhase());
    try std.testing.expectEqual(@as(?u64, 2), client.localOneRttKeyUpdateCount());
    try std.testing.expectEqual(@as(?bool, false), client.localOneRttRetainsKeyGeneration(1));
    try std.testing.expectEqual(@as(?bool, true), client.localOneRttRetainsKeyGeneration(2));
    try std.testing.expectEqual(@as(?bool, true), client.localOneRttRetainsKeyGeneration(3));
    try std.testing.expectEqual(@as(?u64, 1), client.pendingOneRttKeyUpdateAckThreshold());

    try client.sendPing();
    const second_ping = (try client.pollProtectedShortDatagramWithInstalledKeys(
        14,
        &server_dcid,
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(second_ping);
    try server.processProtectedShortDatagramWithInstalledKeys(15, server_dcid.len, second_ping);
    try std.testing.expectEqual(@as(?bool, false), server.peerOneRttKeyPhase());
    try std.testing.expectEqual(@as(?u64, 2), server.peerOneRttKeyUpdateCount());
    try std.testing.expectEqual(@as(?bool, false), server.peerOneRttRetainsKeyGeneration(1));
    try std.testing.expectEqual(@as(?bool, true), server.peerOneRttRetainsKeyGeneration(2));
    try std.testing.expectEqual(@as(?bool, true), server.peerOneRttRetainsKeyGeneration(3));
    const stale_generation_1_keys = protection.nextAes128PacketProtectionKeys(secrets.client);
    const stale_ping_plaintext = [_]u8{
        @intFromEnum(frame.FrameType.ping),
        @intFromEnum(frame.FrameType.padding),
        @intFromEnum(frame.FrameType.padding),
    };
    const stale_generation_1_ping = try protection.protectShortPacketAes128(
        std.testing.allocator,
        .{
            .dcid = &server_dcid,
            .key_phase = true,
            .packet_number = 2,
        },
        try packet.encodePacketNumberForHeader(2, null),
        stale_generation_1_keys,
        &stale_ping_plaintext,
    );
    defer std.testing.allocator.free(stale_generation_1_ping);
    try std.testing.expectError(
        error.InvalidPacket,
        server.processProtectedShortDatagramWithInstalledKeys(16, server_dcid.len, stale_generation_1_ping),
    );
    try std.testing.expectEqual(@as(u64, 2), server.nextPeerPacketNumber(.application));
    try std.testing.expectEqual(@as(?u64, 1), server.pendingAckLargest(.application));
    try std.testing.expectEqual(@as(?u64, 2), server.peerOneRttKeyUpdateCount());
    const second_ack = (try server.pollProtectedShortDatagramWithInstalledKeys(
        17,
        &client_dcid,
    )) orelse return error.TestUnexpectedResult;
    defer std.testing.allocator.free(second_ack);
    try client.processProtectedShortDatagramWithInstalledKeys(18, client_dcid.len, second_ack);
    try std.testing.expectEqual(@as(?u64, null), client.pendingOneRttKeyUpdateAckThreshold());
}

test "installed one RTT key update ACK confirmation rolls back with invalid payload" {
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);

    var client = try Connection.init(std.testing.allocator, .client, .{});
    defer client.deinit();
    try client.installOneRttTrafficSecrets(.{
        .local = secrets.client.secret,
        .peer = secrets.server.secret,
    });
    try client.confirmHandshake();
    try client.initiateOneRttKeyUpdate();
    _ = try client.recordPacketSentInSpace(.application, 10, 100);

    var payload: [32]u8 = undefined;
    var out = buffer.fixedWriter(&payload);
    try frame.encodeFrame(out.writer(), .{ .ack = .{
        .largest_acknowledged = 0,
        .ack_delay = 0,
        .first_ack_range = 0,
    } });
    try out.writeByte(0xff);
    try std.testing.expectError(error.InvalidPacket, client.processDatagramForPacketType(.one_rtt, 20, out.getWritten()));
    try std.testing.expectError(error.InvalidPacket, client.initiateOneRttKeyUpdate());
    try std.testing.expectEqual(@as(usize, 1), client.sent_packets.items.len);

    out = buffer.fixedWriter(&payload);
    try frame.encodeFrame(out.writer(), .{ .ack = .{
        .largest_acknowledged = 0,
        .ack_delay = 0,
        .first_ack_range = 0,
    } });
    try client.processDatagramForPacketType(.one_rtt, 21, out.getWritten());
    try client.initiateOneRttKeyUpdate();
}

test "processProtectedShortDatagram rejects invalid short packets without mutation" {
    const original_dcid = [_]u8{ 0x83, 0x94, 0xc8, 0xf0, 0x3e, 0x51, 0x57, 0x08 };
    const server_dcid = [_]u8{ 0xaa, 0xbb, 0xcc, 0xdd };
    const secrets = try protection.deriveInitialSecrets(.v1, &original_dcid);
    const plaintext = [_]u8{
        @intFromEnum(frame.FrameType.ping),
        @intFromEnum(frame.FrameType.padding),
        @intFromEnum(frame.FrameType.padding),
        @intFromEnum(frame.FrameType.padding),
    };

    var server = try Connection.init(std.testing.allocator, .server, .{});
    defer server.deinit();

    const wrong_packet_number = try protection.protectShortPacketAes128(std.testing.allocator, .{
        .dcid = &server_dcid,
        .spin_bit = false,
        .key_phase = false,
        .packet_number = 1,
    }, try packet.encodePacketNumberForHeader(1, null), secrets.client, &plaintext);
    defer std.testing.allocator.free(wrong_packet_number);

    try std.testing.expectError(
        error.InvalidPacket,
        server.processProtectedShortDatagram(10, secrets.client, server_dcid.len, wrong_packet_number),
    );
    try std.testing.expectEqual(@as(u64, 0), server.nextPeerPacketNumber(.application));
    try std.testing.expectEqual(@as(?u64, null), server.pendingAckLargest(.application));

    const tampered = try protection.protectShortPacketAes128(std.testing.allocator, .{
        .dcid = &server_dcid,
        .spin_bit = false,
        .key_phase = false,
        .packet_number = 0,
    }, try packet.encodePacketNumberForHeader(0, null), secrets.client, &plaintext);
    defer std.testing.allocator.free(tampered);
    tampered[tampered.len - 1] ^= 0x01;

    try std.testing.expectError(
        error.InvalidPacket,
        server.processProtectedShortDatagram(11, secrets.client, server_dcid.len, tampered),
    );
    try std.testing.expectEqual(@as(u64, 0), server.nextPeerPacketNumber(.application));
    try std.testing.expectEqual(@as(?u64, null), server.pendingAckLargest(.application));
}

