test "streamState reports FIN send and receive final-size snapshots" {
    var client = try Connection.init(std.testing.allocator, .client, .{});
    defer client.deinit();
    var server = try Connection.init(std.testing.allocator, .server, .{});
    defer server.deinit();
    try server.validatePeerAddress();

    try std.testing.expect((try client.streamState(0)) == null);
    try std.testing.expectError(error.InvalidStream, client.streamState(max_quic_varint + 1));

    const stream_id = try client.openStream();
    try client.sendOnStream(stream_id, "hello", true);

    const client_state = (try client.streamState(stream_id)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(stream_id, client_state.stream_id);
    try std.testing.expectEqual(StreamSendState.data_sent, client_state.send);
    try std.testing.expectEqual(StreamReceiveState.none, client_state.receive);
    try std.testing.expectEqual(@as(?u64, 5), client_state.send_offset);
    try std.testing.expect(client_state.send_max_data != null);
    try std.testing.expectEqual(@as(?u64, null), client_state.receive_buffered);

    var datagram: [128]u8 = undefined;
    try server.processDatagram(0, (try client.pollTx(0, &datagram)).?);

    const server_received = (try server.streamState(stream_id)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(StreamSendState.none, server_received.send);
    try std.testing.expectEqual(StreamReceiveState.data_received, server_received.receive);
    try std.testing.expectEqual(@as(?u64, 5), server_received.receive_buffered);
    try std.testing.expectEqual(@as(?u64, 0), server_received.receive_read_offset);
    try std.testing.expectEqual(@as(?u64, 5), server_received.receive_final_size);
    try std.testing.expectEqual(@as(?u64, null), server_received.receive_reset_error_code);

    var read_buf: [5]u8 = undefined;
    const n = (try server.recvOnStream(stream_id, &read_buf)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqualStrings("hello", read_buf[0..n]);

    const server_read = (try server.streamState(stream_id)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(StreamReceiveState.data_read, server_read.receive);
    try std.testing.expectEqual(@as(?u64, 5), server_read.receive_read_offset);

    try client.receiveAckInSpace(.application, 2, .{
        .largest_acknowledged = 0,
        .ack_delay = 0,
        .first_ack_range = 0,
    });
    const client_acked = (try client.streamState(stream_id)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(StreamSendState.data_acked, client_acked.send);

    var split_client = try Connection.init(std.testing.allocator, .client, .{});
    defer split_client.deinit();
    const split_stream_id = try split_client.openStream();
    try split_client.sendOnStream(split_stream_id, "a", false);
    try split_client.sendOnStream(split_stream_id, "b", true);
    _ = (try split_client.pollTx(0, &datagram)).?;
    _ = (try split_client.pollTx(1, &datagram)).?;

    try split_client.receiveAckInSpace(.application, 2, .{
        .largest_acknowledged = 1,
        .ack_delay = 0,
        .first_ack_range = 0,
    });
    const split_fin_acked = (try split_client.streamState(split_stream_id)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(StreamSendState.data_sent, split_fin_acked.send);

    try split_client.receiveAckInSpace(.application, 3, .{
        .largest_acknowledged = 0,
        .ack_delay = 0,
        .first_ack_range = 0,
    });
    const split_data_acked = (try split_client.streamState(split_stream_id)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(StreamSendState.data_acked, split_data_acked.send);

    var zero_client = try Connection.init(std.testing.allocator, .client, .{});
    defer zero_client.deinit();
    var zero_server = try Connection.init(std.testing.allocator, .server, .{});
    defer zero_server.deinit();
    try zero_server.validatePeerAddress();

    const zero_stream_id = try zero_client.openStream();
    try zero_client.sendOnStream(zero_stream_id, "", true);
    try zero_server.processDatagram(1, (try zero_client.pollTx(1, &datagram)).?);

    const zero_received = (try zero_server.streamState(zero_stream_id)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(StreamReceiveState.data_received, zero_received.receive);
    try std.testing.expectEqual(@as(?u64, 0), zero_received.receive_buffered);
    try std.testing.expectEqual(@as(?u64, 0), zero_received.receive_final_size);

    try std.testing.expectEqual(@as(?usize, null), try zero_server.recvOnStream(zero_stream_id, &read_buf));

    const zero_read = (try zero_server.streamState(zero_stream_id)) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqual(StreamReceiveState.data_read, zero_read.receive);
    try std.testing.expectEqual(@as(?u64, 0), zero_read.receive_read_offset);
}

